import React, { useState } from 'react';

interface Props {
  title: string;
}

export function MyComponent({ title }: Props) {
  const [count, setCount] = useState(0);

  return (
    <div>
      <h2>{title}</h2>
      <p>Count: {count}</p>
      <button onClick={() => setCount(count + 1)}>
        Increment
      </button>
    </div>
  );
}
